package com.example.offlineshapealarm.challenge
import android.graphics.*; import com.facebook.react.bridge.*; import kotlin.math.*
object ShapeAnalyzer { private const val MIN_BRIGHTNESS=35.0; fun analyze(path:String, target:String, difficulty:String): WritableMap { val start=System.currentTimeMillis(); val bitmap=BitmapFactory.decodeFile(path) ?: return result(false,0.0,target,"processing-failed",System.currentTimeMillis()-start,null); val scale=720.0 / max(bitmap.width, bitmap.height).coerceAtLeast(1); val w=if(scale<1) (bitmap.width*scale).roundToInt() else bitmap.width; val h=if(scale<1) (bitmap.height*scale).roundToInt() else bitmap.height; val bmp=if(w!=bitmap.width) Bitmap.createScaledBitmap(bitmap,w,h,true) else bitmap; var sum=0.0; val pixels=IntArray(w*h); bmp.getPixels(pixels,0,w,0,0,w,h); val gray=DoubleArray(pixels.size); for(i in pixels.indices){ val c=pixels[i]; val g=(Color.red(c)*0.299+Color.green(c)*0.587+Color.blue(c)*0.114); gray[i]=g; sum+=g }; val mean=sum/gray.size; if(mean<MIN_BRIGHTNESS) return result(false,0.0,target,"image-too-dark",System.currentTimeMillis()-start,null,w,h,mean); val threshold=if(mean>128) mean-35 else mean+35; val foreground=BooleanArray(gray.size){ if(mean>128) gray[it] < threshold else gray[it] > threshold }; val visited=BooleanArray(gray.size); var best: Box?=null; var second=0; var count=0; val q=IntArray(foreground.size); for(i in foreground.indices){ if(!foreground[i]||visited[i]) continue; var head=0; var tail=0; visited[i]=true; q[tail++]=i; var minX=w; var maxX=0; var minY=h; var maxY=0; var area=0; while(head<tail){ val p=q[head++]; val x=p%w; val y=p/w; area++; if(x<minX)minX=x; if(x>maxX)maxX=x; if(y<minY)minY=y; if(y>maxY)maxY=y; val ns=intArrayOf(p-1,p+1,p-w,p+w); for(n in ns){ if(n<0||n>=foreground.size||visited[n]||!foreground[n]) continue; val nx=n%w; if(abs(nx-x)>1) continue; visited[n]=true; q[tail++]=n } }; if(area > w*h*0.01){ count++; val box=Box(minX,minY,maxX-minX+1,maxY-minY+1,area); if(best==null || area>best!!.area){ second=best?.area ?: 0; best=box } else if(area>second) second=area } }; val b=best ?: return result(false,0.0,target,"no-object-found",System.currentTimeMillis()-start,null,w,h,mean,count); val areaRatio=b.area.toDouble()/(w*h); if(areaRatio<0.05) return result(false,0.0,target,"object-too-small",System.currentTimeMillis()-start,features(b,w,h),w,h,mean,count); val border=(if(b.x<=2) b.height else 0)+(if(b.y<=2) b.width else 0)+(if(b.x+b.width>=w-2) b.height else 0)+(if(b.y+b.height>=h-2) b.width else 0); val borderRatio=border.toDouble()/(2.0*(b.width+b.height).coerceAtLeast(1)); if(borderRatio>0.2) return result(false,0.0,target,"object-touches-border",System.currentTimeMillis()-start,features(b,w,h,borderRatio),w,h,mean,count); if(second > b.area*0.65) return result(false,0.25,target,"multiple-objects",System.currentTimeMillis()-start,features(b,w,h,borderRatio),w,h,mean,count); val ratio=max(b.width,b.height).toDouble()/min(b.width,b.height).coerceAtLeast(1); val aspectScore=((ratio-1.5)/2.5).coerceIn(0.0,1.0); val sizeScore=if(areaRatio in 0.15..0.45) 1.0 else if(areaRatio<0.15) ((areaRatio-0.05)/0.1).coerceIn(0.0,1.0) else ((0.7-areaRatio)/0.25).coerceIn(0.0,1.0); val dominant=if(second==0)1.0 else (1.0-second.toDouble()/b.area).coerceIn(0.0,1.0); val confidence=(aspectScore*0.4+sizeScore*0.15+0.15+dominant*0.15+0.15).coerceIn(0.0,1.0); val thresholdScore=when(difficulty){"easy"->0.55;"hard"->0.80;else->0.68}; val accepted=confidence>=thresholdScore && ratio>=2.3 && areaRatio<=0.70; return result(accepted,confidence,target,if(accepted)null else "shape-does-not-match",System.currentTimeMillis()-start,features(b,w,h,borderRatio),w,h,mean,count) }
 private data class Box(val x:Int,val y:Int,val width:Int,val height:Int,val area:Int)
 private fun features(b:Box,w:Int,h:Int,border:Double=0.0): WritableMap { val m=Arguments.createMap(); val bb=Arguments.createMap(); bb.putInt("x",b.x); bb.putInt("y",b.y); bb.putInt("width",b.width); bb.putInt("height",b.height); val ar=max(b.width,b.height).toDouble()/min(b.width,b.height).coerceAtLeast(1); val extent=b.area.toDouble()/(b.width*b.height).coerceAtLeast(1); m.putDouble("contourArea",b.area.toDouble()); m.putDouble("imageAreaRatio",b.area.toDouble()/(w*h)); m.putDouble("perimeter",(2*(b.width+b.height)).toDouble()); m.putMap("boundingBox",bb); m.putDouble("aspectRatio",b.width.toDouble()/b.height.coerceAtLeast(1)); m.putDouble("orientedAspectRatio",ar); m.putDouble("circularity",0.0); m.putDouble("solidity",extent.coerceIn(0.0,1.0)); m.putDouble("extent",extent); m.putInt("cornerCount",4); m.putDouble("borderContactRatio",border); return m }
 private fun result(ok:Boolean, conf:Double, target:String, reason:String?, ms:Long, f:WritableMap?, w:Int?=null,h:Int?=null,mean:Double?=null,contours:Int?=null): WritableMap { val m=Arguments.createMap(); m.putBoolean("accepted",ok); m.putDouble("confidence",conf); m.putString("targetShapeId",target); if(reason!=null)m.putString("failureReason",reason); m.putDouble("processingDurationMs",ms.toDouble()); if(f!=null)m.putMap("features",f); val d=Arguments.createMap(); w?.let{d.putInt("imageWidth",it)}; h?.let{d.putInt("imageHeight",it)}; mean?.let{d.putDouble("meanBrightness",it)}; contours?.let{d.putInt("contourCount",it)}; m.putMap("diagnostics",d); return m }
}
